Here's the complete setup:

**Program.cs**

```csharp
using System.Diagnostics;
using System.Diagnostics.Metrics;
using OpenTelemetry.Metrics;
using OpenTelemetry.Resources;
using OpenTelemetry.Trace;

var builder = WebApplication.CreateBuilder(args);

var serviceName = "OrderApi";
var serviceVersion = "1.0.0";

builder.Services.AddOpenTelemetry()
    .ConfigureResource(r => r.AddService(
        serviceName: serviceName,
        serviceVersion: serviceVersion))
    .WithTracing(tracing => tracing
        .AddAspNetCoreInstrumentation()
        .AddHttpClientInstrumentation()
        .AddSource(OrderService.ActivitySourceName)
        .AddOtlpExporter(opts =>
        {
            opts.Endpoint = new Uri("http://localhost:4317");
        }))
    .WithMetrics(metrics => metrics
        .AddAspNetCoreInstrumentation()
        .AddMeter(OrderService.MeterName)
        .AddOtlpExporter(opts =>
        {
            opts.Endpoint = new Uri("http://localhost:4317");
        }));

builder.Services.AddSingleton<OrderService>();

var app = builder.Build();

app.MapPost("/orders", async (OrderRequest request, OrderService svc) =>
{
    var result = await svc.ProcessOrder(request);
    return Results.Ok(result);
});

app.Run();

public record OrderRequest(string CustomerId, string ProductId, int Quantity);
public record OrderResult(string OrderId, string Status);
```

**OrderService.cs**

```csharp
using System.Diagnostics;
using System.Diagnostics.Metrics;

public class OrderService
{
    public const string ActivitySourceName = "OrderApi.OrderService";
    public const string MeterName = "OrderApi.OrderService";

    private static readonly ActivitySource ActivitySource = new(ActivitySourceName);
    private static readonly Meter Meter = new(MeterName);
    private static readonly Counter<long> OrdersProcessed = Meter.CreateCounter<long>(
        "orders.processed",
        unit: "{order}",
        description: "Number of orders processed");

    public async Task<OrderResult> ProcessOrder(OrderRequest request)
    {
        using var activity = ActivitySource.StartActivity("OrderService.ProcessOrder");
        activity?.SetTag("order.customer_id", request.CustomerId);
        activity?.SetTag("order.product_id", request.ProductId);
        activity?.SetTag("order.quantity", request.Quantity);

        // Simulate processing
        await Task.Delay(50);

        var orderId = Guid.NewGuid().ToString("N")[..8];

        activity?.SetTag("order.id", orderId);
        activity?.SetStatus(ActivityStatusCode.Ok);

        OrdersProcessed.Add(1, new TagList
        {
            { "customer.id", request.CustomerId },
            { "order.status", "completed" }
        });

        return new OrderResult(orderId, "completed");
    }
}
```

**Required packages:**

```bash
dotnet add package OpenTelemetry.Extensions.Hosting
dotnet add package OpenTelemetry.Instrumentation.AspNetCore
dotnet add package OpenTelemetry.Instrumentation.Http
dotnet add package OpenTelemetry.Exporter.OpenTelemetryProtocol
```

**Key points:**
- `ActivitySource` is .NET's API for creating spans — registered via `.AddSource()`
- `Meter`/`Counter<T>` are the metrics APIs — registered via `.AddMeter()`
- OTLP exporter sends to `localhost:4317` (gRPC) by default; adjust for your collector
- The `?.` null-check on `activity` handles the case where no listener is sampling that span
